class AgentState(TypedDict):
    messages: List[str]
    facts: dict
    ground_truth: dict  # Immutable verified facts

# Bootstrap node
def ground_truth_loader(state: AgentState) -> AgentState:
    state['ground_truth'] = {
        'usa_population': '331e6',
        'japan_population': '125e6',
        'sources': ['census.gov', 'worldbank.org']
    }
    return state

# Validation node
def validate_against_truth(state: AgentState) -> AgentState:
    for key, value in state['facts'].items():
        truth_key = key.replace(' ', '_')
        if truth_key in state['ground_truth'] and str(value) != state['ground_truth'][truth_key]:
            state['messages'].append(f"[CORRECTION] {key}: {state['ground_truth'][truth_key]}")
            state['facts'][key] = state['ground_truth'][truth_key]
    return state

graph.add_node('ground_truth', ground_truth_loader)
graph.add_node('validate', validate_against_truth)

