class AgentState(TypedDict):
    messages: List[str]
    confidence: float
    needs_review: bool

# Confidence-based routing
def route_hallucination_risk(state: AgentState):
    if state.get('confidence', 0) > 0.9 and 'uncertain' in state['messages'][-1].lower():
        return "human_review"  # Force review despite high confidence
    return "continue"

