from pydantic import BaseModel, Field, validator
from typing import Dict, Any

class ValidatedState(BaseModel):
    messages: list[str] = Field(..., max_items=50)
    facts: Dict[str, str] = {}
    sources: list[str] = Field(default_factory=list, min_items=1)

    @validator('facts')
    def facts_must_have_sources(cls, v):
        if v and not any('source' in k.lower() for k in v):
            raise ValueError('Facts must reference sources')
        return v

# Wrap state in graph
def validated_node(state: AgentState) -> AgentState:
    validated = ValidatedState(**state).dict()
    return {**state, **validated}

graph.add_node('validate_schema', validated_node)
